#!/usr/bin/env python3
"""
Reintento automatico para envios de WhatsApp ante errores
transitorios de Meta (is_transient: true / code: 2, 'retry your
request later'). Hasta 2 reintentos con espera creciente (1s, 2s).
Esto deberia reducir respuestas perdidas por hiccups pasajeros de
la API de Meta, tanto para texto como para fotos de servicios.

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_whatsapp_retry_transient.py
"""

import base64
from pathlib import Path

WHATSAPP_LIB_B64 = """"""

def main():
    p = Path("src/lib/whatsapp.ts")
    p.write_bytes(base64.b64decode(WHATSAPP_LIB_B64))
    print(f"escrito: {p} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'WhatsApp: reintento ante errores transitorios de Meta'")
    print("  git push")

if __name__ == "__main__":
    main()